GET /prompt-fragments?user_id= <p>Get aggregated skill prompt fragments for one user.</p> <p>Response 200:</p> <pre><code>{
  "fragments": [
    "[Tasks: 3 open, 1 overdue]"
  ]
}
</code></pre>

POST /handle <p>Dispatch one request to the mapped skill.</p> <p>Request:</p> <pre><code>{
  "id": "optional-uuid",
  "user_id": "123456789",
  "intent": "email_route",
  "message": "route unread email",
  "context": {
    "skill_name": "email",
    "provider": "google",
    "limit": 20
  }
}
</code></pre> <p>Response 200:</p> <pre><code>{
  "request_id": "...",
  "success": true,
  "message": "Processed 2 unread email(s) via google.",
  "data": {},
  "error": null,
  "actions": []
}
</code></pre> <p>Response 400: invalid JSON or request shape</p> <p>Response 500: unexpected internal failure</p>

POST /heartbeat <p>Run heartbeat actions for provided users.</p> <p>Request:</p> <pre><code>{
  "user_ids": ["123456789", "987654321"]
}
</code></pre> <p>Response 200:</p> <pre><code>{
  "actions": [
    {
      "skill_name": "gmail",
      "action_type": "send_message",
      "user_id": "123456789",
      "data": {
        "message": "Email digest is ready."
      },
      "priority": 3
    }
  ]
}
</code></pre> <p>Actions are returned in descending priority order (higher number first).</p>

DELETE /settings/{namespace}/{key}?deleted_by= <p>Delete one runtime override.</p> <p>Response 200:</p> <pre><code>{
  "ok": true,
  "existed": true
}
</code></pre>

PUT /secrets/{name} <p>Set one encrypted secret.</p> <p>Request:</p> <pre><code>{
  "value": "secret-value",
  "changed_by": "123456789",
  "description": "Google OAuth client secret"
}
</code></pre> <p>Response 200:</p> <pre><code>{
  "ok": true
}
</code></pre>

DELETE /secrets/{name}?deleted_by= <p>Delete one stored secret.</p> <p>Response 200:</p> <pre><code>{
  "ok": true,
  "existed": true
}
</code></pre>
